var stripSpaces = (str) => str.replace(/\s+/g, "");
var hexToUint8Array = (hex) => new Uint8Array(hex.match(/.{1,2}/g).map((byte) => parseInt(byte, 16)));
function base64ToUint8Array(base64) {
  const normalizedBase64 = base64.replace(/-/g, "+").replace(/_/g, "/");
  const paddedBase64 = normalizedBase64.padEnd(normalizedBase64.length + (4 - normalizedBase64.length % 4) % 4, "=");
  return Uint8Array.from(atob(paddedBase64), (c2) => c2.charCodeAt(0));
}
var uint8ArrayToBase64 = (data2) => btoa(String.fromCharCode.apply(null, data2));
function parseHexOrB64ToUint8Array(text2) {
  let inputData;
  const textData = stripSpaces(text2);
  if (/^[0-9a-fA-F]+$/.test(textData)) {
    inputData = hexToUint8Array(textData);
  } else {
    inputData = base64ToUint8Array(textData);
  }
  return inputData;
}

// src/worker.ts
var FFLModule;
var offscreenCanvas;
var workerRenderer;
function log3(...message) {
  console.log("[FFLWorker]", ...message);
}
function initRenderer() {
  workerRenderer = new WebGLRenderer({
    antialias: true,
    alpha: true,
    canvas: offscreenCanvas
  });
}
self.onmessage = async (e) => {
  log3("Message received from main script", e);
  const input = e.data;
  switch (input.type) {
    case "Init": {
      log3("Loading FFL Module");
      FFLModule = (await Promise.resolve().then(() => (init_ffl_emscripten(), exports_ffl_emscripten))).default.Module;
      log3("Initialized Module!", FFLModule);
      log3("Loading FFL Resource...");
      await loadBodyModels();
      await initializeFFLWithResource(input.resourcePath, FFLModule);
      log3("Loaded FFL Resource!");
      offscreenCanvas = input.offscreenCanvas;
      initRenderer();
      postMessage({ ready: true });
      break;
    }
    case "MakeIcon": {
      log3("Call MakeIcon");
      var then = performance.now();
      let dataURL = {
        type: "dataURL",
        result: ""
      }, model;
      try {
        const dataU8 = input.data;
        model = createCharModel(dataU8, undefined, LUTShaderMaterial, FFLModule, false);
        initCharModelTextures(model, workerRenderer);
        let realView = ViewType.MakeIcon;
        switch (input.view) {
          case "face":
          case "variableiconbody":
            realView = ViewType.MakeIcon;
            break;
          case "all_body_sugar":
            realView = ViewType.MakeIcon;
            break;
        }
        dataURL = await createCharModelIcon(model, workerRenderer, realView, 512, 512);
      } catch (e2) {
        console.error(`Library error: Could not make icon`, e2);
      } finally {
        model.dispose();
        var now2 = performance.now();
        log3(`Got it in ${(now2 - then).toFixed(0)}ms! Sending to main thread.`);
        var url = undefined;
        if (dataURL.type === "blob") {
          url = URL.createObjectURL(dataURL.result);
          setTimeout(() => {
            URL.revokeObjectURL(url);
          }, 500);
        }
        postMessage({ id: input.id, result: url || dataURL.result });
      }
    }
  }
};
